var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그라운드 원 도시관리국에서 안내드립니다.</color>","JPN":"<color=#ffd34c>グラウンド・ワンの都市管理局からお知らせします。</color>","ENG":"<color=#ffd34c>This is an announcement from Ground One, City Management.</color>","TWN":"<color=#ffd34c>G1城市管理局通知。</color>"},"stage":{"bg":"GROUND_ONE","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 대균열을 중심으로 연쇄적 현실 붕괴 현상이 관측되었습니다.</color>","JPN":"<color=#ffd34c>ただいま、大亀裂を中心に連鎖的な現実の崩壊現象が観測されました。</color>","ENG":"<color=#ffd34c>Multiple chain of reality collapses are currently being observed in the center of the Grand Dimension Crevice.</color>","TWN":"<color=#ffd34c>目前以大峽谷為中心，觀測到連鎖的現實崩壞現象。</color>"},"stage":{"bg":"GROUND_ONE","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>법령에 의거, 그라운드 원 소재의 전 태스크포스는 그라운드 원 방어를 위한 총력전에 동원됩니다.</color>","JPN":"<color=#ffd34c>法令により、グラウンド・ワン所在の全タスクフォースはグラウンド・ワン防御のための総力戦に動員されます。</color>","ENG":"<color=#ffd34c>By statute, all TASKFORCE at Ground One are to mobilize and defend Ground One.</color>","TWN":"<color=#ffd34c>依法，G1所有的特遣勢力將全體動員保護G1。</color>"},"stage":{"bg":"GROUND_ONE","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>전 태스크포스는 즉시 전투 태세로 소집에 응해 주시기 바랍니다. 이것은 실제 상황입니다.</color>","JPN":"<color=#ffd34c>全タスクフォースは直ちに戦闘態勢で招集に応じてください。これは訓練ではありません。</color>","ENG":"<color=#ffd34c>All TASKFORCE, prepare to engage in combat immediately. This is not a drill.</color>","TWN":"<color=#ffd34c>請所有特遣勢力立刻集合進入作戰狀態，這不是演習。</color>"},"stage":{"bg":"GROUND_ONE","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"보여, 오르카?","JPN":"オルカ、見える？","ENG":"Can you see it, Orca?","TWN":"奧爾卡，你有看到嗎？"},"stage":{"bg":"MS_1006","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"저기 보이는 곳 너머에 우리의 고향이 있어.","JPN":"あの向こうに私たちの故郷があるの。","ENG":"That over there is where our home is.","TWN":"那裡的另一邊就是我們的家鄉。"},"stage":{"bg":"MS_1006","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저기라니, 대균열 말씀이세요? 갑자기 나타나서 그게 무슨……?","JPN":"あそこって、大亀裂のことですか？　いきなり現れて何を……？","ENG":"Are you referring to the Grand Dimension Crevice? I don't understand a word you're─","TWN":"什麼那裡？你是說大峽谷嗎？你突然冒出來在胡說……？"},"stage":{"bg":"MS_1006","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"물론 주소지가 저기란 뜻은 아니구요.","JPN":"もちろんあそこに家があるってことじゃないよ。","ENG":"I don't mean THAT is our home, but...","TWN":"我的意思當然不是真的指那裡。"},"stage":{"bg":"MS_1006","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"인간들은 지구를 자기들 고향이라고 부르잖아요?","JPN":"人間たちは地球を故郷って呼んでるでしょ？","ENG":"You know how humans call Earth their home?","TWN":"人類不是都把地球稱為自己的家鄉嗎？"},"stage":{"bg":"MS_1006","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"저에게는 당신들이 두려워하는 저 너머가 바로 고향이에요.","JPN":"それと同じで、私にはあなたたちが怖がるあそこが故郷なのよ。","ENG":"Well, my home is over on that side that you all fear so much.","TWN":"對我而言，你們害怕的另一邊就是我的家鄉。"},"stage":{"bg":"MS_1006","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"차갑고 고요한, 우리가 헤엄치던 바다.","JPN":"冷たくて静かな、私たちが泳いでいた海。","ENG":"The cold and silent ocean we used to swim in.","TWN":"冰冷又寂靜，我們徜徉的大海。"},"stage":{"bg":"MS_1006","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"도망쳐라. 어서.","JPN":"逃げろ。早く。","ENG":"Run. Now.","TWN":"快逃！"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"어째서 도망쳐야 해? 위험한 사람이야?","JPN":"どうして逃げないとダメなの？　危ない人？","ENG":"Why do I have to run? Is she a dangerous person?","TWN":"為什麼要逃？她是危險人物嗎？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"기억이 떠올랐다.","JPN":"思い出した。","ENG":"My memories came back.","TWN":"我想起來了。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"저건 <color=#ffd34c>나</color>다. 이성적인 포식자로서의 나.","JPN":"あれは<color=#ffd34c>私</color>だ。理性的な飽食者としての私。","ENG":"That's <color=#ffd34c>me</color>. The rational predator side of me.","TWN":"她就是<color=#ffd34c>我</color>，是屬於理性掠食者的我。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_RED","text":{"KOREA":"본래라면 본능을 차지하는 나와 대등한 위치지만, 지금은 아니야.","JPN":"本来なら本能を支配する私と同等な位置だが、今は違う。","ENG":"Originally, she and I would be equal in power, but that's not the case now.","TWN":"原本和佔據本能的我地位是平等的，但現在不是。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That’s...","TWN":"那是……"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_RED","face":"UNIT_IDLE"}}}}]`);export{e as default};